import{_ as n,c as t,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse(`{"title":"Einführung: Lokaler AI-Gateway | Antigravity Manager","description":"Verstehen Sie die Kernposition von Antigravity Manager. Es bietet eine Desktop-Anwendung und einen lokalen HTTP-Gateway, unterstützt Multi-Protokoll-Endpunkte und Kontopool-Scheduling, hilft Ihnen beim schnellen Einstieg in lokale Reverse-Proxies und vermeidet häufige Konfigurationsfehler.","frontmatter":{"title":"Einführung: Lokaler AI-Gateway | Antigravity Manager","sidebarTitle":"Was ist ein lokaler AI-Gateway?","subtitle":"Was Antigravity Tools ist: Ein lokaler AI-Gateway aus 'Konto + Protokoll'","description":"Verstehen Sie die Kernposition von Antigravity Manager. Es bietet eine Desktop-Anwendung und einen lokalen HTTP-Gateway, unterstützt Multi-Protokoll-Endpunkte und Kontopool-Scheduling, hilft Ihnen beim schnellen Einstieg in lokale Reverse-Proxies und vermeidet häufige Konfigurationsfehler.","tags":["Erste Schritte","Konzepte","Lokaler Gateway","API-Proxy"],"prerequisite":[],"order":1},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/start/getting-started/index.md","filePath":"de/lbjlaq/Antigravity-Manager/start/getting-started/index.md"}`),a={name:"de/lbjlaq/Antigravity-Manager/start/getting-started/index.md"};function o(l,e,s,d,u,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="was-antigravity-tools-ist-ein-lokaler-ai-gateway-aus-konto-protokoll" tabindex="-1">Was Antigravity Tools ist: Ein lokaler AI-Gateway aus &quot;Konto + Protokoll&quot; <a class="header-anchor" href="#was-antigravity-tools-ist-ein-lokaler-ai-gateway-aus-konto-protokoll" aria-label="Permalink to &quot;Was Antigravity Tools ist: Ein lokaler AI-Gateway aus &quot;Konto + Protokoll&quot;&quot;">​</a></h1><p>Die Eintrittsbarriere für viele AI-Clients/SDKs liegt nicht darin, &quot;wie man die API aufruft&quot;, sondern in &quot;welchem Protokoll Sie sich verbinden, wie Sie mehrere Konten verwalten, wie Sie bei Fehlern automatisch wiederherstellen&quot;. Antigravity Tools versucht, diese drei Dinge in einen lokalen Gateway zu konvergieren.</p><h2 id="was-sind-antigravity-tools" tabindex="-1">Was sind Antigravity Tools? <a class="header-anchor" href="#was-sind-antigravity-tools" aria-label="Permalink to &quot;Was sind Antigravity Tools?&quot;">​</a></h2><p><strong>Antigravity Tools</strong> ist eine Desktop-Anwendung: Sie verwalten Konten und Konfigurationen in der GUI, sie startet einen HTTP-Reverse-Proxy-Dienst auf Ihrem lokalen Computer, leitet Anfragen von verschiedenen Herstellern/Protokollen einheitlich an den Upstream weiter und konvertiert die Antworten zurück in ein für den Client vertrautes Format.</p><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><ul><li>Klären, welches Problem Antigravity Tools löst (und welches es nicht löst)</li><li>Seine Kernkomponenten erkennen: GUI, Kontopool, HTTP-Reverse-Proxy-Gateway, Protokoll-Adapter</li><li>Die Standard-Sicherheitsgrenzen verstehen (127.0.0.1, Port, Authentifizierungsmodus) und wann sie geändert werden müssen</li><li>Wissen, welchem Kapitel Sie als Nächstes folgen sollten: Installation, Konto hinzufügen, Reverse-Proxy starten, Client einbinden</li></ul><h2 id="ihr-aktuelles-dilemma" tabindex="-1">Ihr aktuelles Dilemma <a class="header-anchor" href="#ihr-aktuelles-dilemma" aria-label="Permalink to &quot;Ihr aktuelles Dilemma&quot;">​</a></h2><p>Vielleicht haben Sie diese Probleme erlebt:</p><ul><li>Ein Client muss drei Protokolle unterstützen (OpenAI/Anthropic/Gemini), die Konfiguration ist oft chaotisch</li><li>Sie haben mehrere Konten, aber das Umschalten, Rotieren und Retry bei Ratenbegrenzung erfolgt manuell</li><li>Wenn Anfragen fehlschlagen, können Sie nur das Protokoll überwachen und raten, ob es &quot;Konto abgelaufen&quot; oder &quot;Upstream-Ratenbegrenzung/Kapazität erschöpft&quot; ist</li></ul><p>Das Ziel von Antigravity Tools ist es, diese &quot;Nebenarbeiten&quot; in einen lokalen Gateway zu integrieren, damit Ihr Client/SDK sich hauptsächlich um eine Sache kümmert: Senden Sie die Anfrage an das lokale System.</p><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Sie können es als einen lokalen &quot;AI-Scheduling-Gateway&quot; verstehen, bestehend aus drei Schichten:</p><ol><li>GUI (Desktop-Anwendung)</li></ol><ul><li>Verantwortlich für die Verwaltung von Konten, Konfigurationen, Überwachung und Statistiken.</li><li>Hauptseite umfasst: Dashboard, Konten, API-Proxy, Überwachung, Token-Statistiken, Einstellungen.</li></ul><ol start="2"><li>HTTP-Reverse-Proxy-Dienst (Axum Server)</li></ol><ul><li>Verantwortlich für die Bereitstellung mehrerer Protokoll-Endpunkte nach außen und die Weiterleitung von Anfragen an den entsprechenden Handler.</li><li>Der Reverse-Proxy-Dienst wird Authentifizierung, Middleware-Überwachung, CORS, Trace und andere Schichten bereitstellen.</li></ul><ol start="3"><li>Kontopool und Scheduling (TokenManager usw.)</li></ol><ul><li>Verantwortlich für die Auswahl verfügbarer Konten aus dem lokalen Kontopool, bei Bedarf Token zu aktualisieren, Rotierung und Selbstheilung durchzuführen.</li></ul><div class="info custom-block"><p class="custom-block-title">Was bedeutet &quot;lokaler Gateway&quot;?</p><p>Hier bedeutet &quot;lokal&quot; das im wörtlichen Sinne: Der Dienst läuft auf Ihrem eigenen Computer, Ihr Client (Claude Code, OpenAI SDK, verschiedene Drittanbieter-Clients) weist die Base URL auf <code>http://127.0.0.1:&lt;port&gt;</code>, die Ankommen, dann leitet Antigravity Tools sie an den Upstream weiter.</p></div><h2 id="welche-endpunkte-stellt-es-bereit" tabindex="-1">Welche Endpunkte stellt es bereit? <a class="header-anchor" href="#welche-endpunkte-stellt-es-bereit" aria-label="Permalink to &quot;Welche Endpunkte stellt es bereit?&quot;">​</a></h2><p>Der Reverse-Proxy-Dienst registriert mehrere Sets von Protokoll-Endpunkten in einem Router. Sie können sich zuerst diese &quot;Eingänge&quot; merken:</p><ul><li>OpenAI-kompatibel: <code>/v1/chat/completions</code>, <code>/v1/completions</code>, <code>/v1/responses</code>, <code>/v1/models</code></li><li>Anthropic-kompatibel: <code>/v1/messages</code>, <code>/v1/messages/count_tokens</code></li><li>Gemini-nativ: <code>/v1beta/models</code>, <code>/v1beta/models/:model</code>, <code>/v1beta/models/:model/countTokens</code></li><li>Gesundheits-Check: <code>GET /healthz</code></li></ul><p>Wenn Ihr Client eines dieser Protokolle unterstützen kann, kann er theoretisch durch Ändern der Base URL Anfragen an diesen lokalen Gateway weiterleiten.</p><h2 id="standard-sicherheitsgrenzen-nicht-uberspringen" tabindex="-1">Standard-Sicherheitsgrenzen (nicht überspringen) <a class="header-anchor" href="#standard-sicherheitsgrenzen-nicht-uberspringen" aria-label="Permalink to &quot;Standard-Sicherheitsgrenzen (nicht überspringen)&quot;">​</a></h2><p>Das größte Problem bei solchen &quot;lokalen Reverse-Proxies&quot; liegt oft nicht in unzureichenden Funktionen, sondern dass Sie sie versehentlich nach außen freigeben.</p><p>Merken Sie sich zuerst einige Standardwerte (alle aus der Standardkonfiguration):</p><ul><li>Standard-Port: <code>8045</code></li><li>Standardmäßig nur lokaler Zugriff: <code>allow_lan_access=false</code>, Überwachungsadresse ist <code>127.0.0.1</code></li><li>Standard-Authentifizierungsmodus: <code>auth_mode=off</code> (verlangt nicht, dass Client einen Schlüssel mitbringt)</li><li>Standardmäßig wird ein <code>sk-...</code>-förmiger <code>api_key</code> generiert (für den Fall, dass Sie Authentifizierung benötigen)</li></ul><div class="warning custom-block"><p class="custom-block-title">Wann müssen Sie Authentifizierung aktivieren?</p><p>Sobald Sie LAN-Zugriff aktivieren (<code>allow_lan_access=true</code>, Überwachungsadresse wird <code>0.0.0.0</code>), sollten Sie gleichzeitig Authentifizierung aktivieren und den API-Schlüssel als Passwort verwalten.</p></div><h2 id="wann-sie-antigravity-tools-verwenden" tabindex="-1">Wann Sie Antigravity Tools verwenden <a class="header-anchor" href="#wann-sie-antigravity-tools-verwenden" aria-label="Permalink to &quot;Wann Sie Antigravity Tools verwenden&quot;">​</a></h2><p>Es eignet sich besser für diese Szenarien:</p><ul><li>Sie haben mehrere AI-Clients/SDKs und möchten sie über eine einheitliche Base URL führen</li><li>Sie müssen verschiedene Protokolle (OpenAI/Anthropic/Gemini) auf denselben &quot;lokalen Ausgang&quot; konvergieren</li><li>Sie haben mehrere Konten und möchten das System für Rotierung und Stabilität verantwortlich machen</li></ul><p>Wenn Sie nur &quot;zwei Zeilen Code schreiben und direkt die offizielle API aufrufen&quot; möchten, und das Konto/Protokoll sehr fest ist, könnte es etwas zu umfangreich sein.</p><h2 id="folgen-sie-mir-richten-sie-zuerst-die-richtige-reihenfolge-ein" tabindex="-1">Folgen Sie mir: Richten Sie zuerst die richtige Reihenfolge ein <a class="header-anchor" href="#folgen-sie-mir-richten-sie-zuerst-die-richtige-reihenfolge-ein" aria-label="Permalink to &quot;Folgen Sie mir: Richten Sie zuerst die richtige Reihenfolge ein&quot;">​</a></h2><p>In dieser Lektion lernen Sie keine detaillierte Konfiguration, sondern richten nur die Hauptreihenfolge ein, um zu vermeiden, dass Sie durch Springen stecken bleiben:</p><h3 id="schritt-1-installieren-dann-starten" tabindex="-1">Schritt 1: Installieren, dann starten <a class="header-anchor" href="#schritt-1-installieren-dann-starten" aria-label="Permalink to &quot;Schritt 1: Installieren, dann starten&quot;">​</a></h3><p><strong>Warum</strong> Die Desktop-Anwendung ist verantwortlich für Kontoverwaltung und Start des Reverse-Proxy-Dienstes; ohne sie sind das spätere OAuth/Reverse-Proxy unmöglich.</p><p>Gehen Sie im nächsten Kapitel nach der README-Installationsmethode vor, um die Installation abzuschließen.</p><p><strong>Was Sie sehen sollten</strong>: Sie können Antigravity Tools öffnen und die Dashboard-Seite sehen.</p><h3 id="schritt-2-fugen-sie-mindestens-ein-konto-hinzu" tabindex="-1">Schritt 2: Fügen Sie mindestens ein Konto hinzu <a class="header-anchor" href="#schritt-2-fugen-sie-mindestens-ein-konto-hinzu" aria-label="Permalink to &quot;Schritt 2: Fügen Sie mindestens ein Konto hinzu&quot;">​</a></h3><p><strong>Warum</strong> Der Reverse-Proxy-Dienst muss eine verfügbare Identität aus dem Kontopool erhalten, um Anfragen an den Upstream zu senden; ohne Konto kann der Gateway auch &quot;für Sie aufrufen&quot; nicht.</p><p>Gehen Sie zum Kapitel &quot;Konto hinzufügen&quot;, fügen Sie das Konto über OAuth oder Refresh-Token-Prozess hinzu.</p><p><strong>Was Sie sehen sollten</strong>: Ihr Konto erscheint auf der Konten-Seite, und Sie können Kontingent/Status-Informationen sehen.</p><h3 id="schritt-3-starten-sie-api-proxy-und-verwenden-sie-healthz-fur-minimale-validierung" tabindex="-1">Schritt 3: Starten Sie API Proxy und verwenden Sie /healthz für minimale Validierung <a class="header-anchor" href="#schritt-3-starten-sie-api-proxy-und-verwenden-sie-healthz-fur-minimale-validierung" aria-label="Permalink to &quot;Schritt 3: Starten Sie API Proxy und verwenden Sie /healthz für minimale Validierung&quot;">​</a></h3><p><strong>Warum</strong> Validieren Sie zuerst mit <code>GET /healthz</code>, dass &quot;lokaler Dienst läuft&quot;, bevor Sie den Client einbinden; die Fehlersuche ist viel einfacher.</p><p>Gehen Sie zum Kapitel &quot;Lokalen Reverse-Proxy starten und ersten Client einbinden&quot;, um den Kreis zu schließen.</p><p><strong>Was Sie sehen sollten</strong>: Ihr Client/SDK kann über die lokale Base URL erfolgreich Antworten erhalten.</p><h2 id="hinweise-zu-fallstricken" tabindex="-1">Hinweise zu Fallstricken <a class="header-anchor" href="#hinweise-zu-fallstricken" aria-label="Permalink to &quot;Hinweise zu Fallstricken&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Szenario</th><th>Was Sie vielleicht tun (❌)</th><th>Empfohlene Vorgehensweise (✓)</th></tr></thead><tbody><tr><td>Möchten, dass Telefon/anderer Computer zugreift</td><td>Direkt <code>allow_lan_access=true</code> öffnen, aber keine Authentifizierung setzen</td><td>Aktivieren Sie gleichzeitig Authentifizierung und validieren Sie zuerst <code>GET /healthz</code> im LAN</td></tr><tr><td>Client meldet 404</td><td>Nur host/port ändern, ohne zu berücksichtigen, wie Client <code>/v1</code> zusammensetzt</td><td>Bestätigen Sie zuerst die Base-URL-Zusammensetzungsstrategie des Clients, bevor Sie entscheiden, ob Sie das <code>/v1</code>-Präfix benötigen</td></tr><tr><td>Fangen sofort mit Claude Code an</td><td>Verbinden Sie direkt komplexen Client, bei Fehler wissen Sie nicht, wo zu suchen</td><td>Führen Sie zuerst den minimalen Kreis aus: Proxy starten -&gt; <code>GET /healthz</code> -&gt; dann Client einbinden</td></tr></tbody></table><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><ul><li>Die Position von Antigravity Tools ist &quot;Desktop-Anwendung + lokaler HTTP-Reverse-Proxy-Gateway&quot;: GUI-Verwaltung, Axum stellt Multi-Protokoll-Endpunkte bereit</li><li>Sie müssen es als lokale Infrastruktur behandeln: zuerst installieren, dann Konto hinzufügen, dann Proxy starten, zuletzt Client einbinden</li><li>Standardmäßig wird nur <code>127.0.0.1:8045</code> überwacht; wenn Sie es an das LAN freigeben, aktivieren Sie unbedingt gleichzeitig Authentifizierung</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion schließen wir den Installationsschritt ab: <strong><a href="./../installation/">Installation und Upgrade: Beste Installationspfad für die Desktop-Anwendung</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Die im README aufgeführten Installationsmethoden (und Prioritäten)</li><li>Die Upgrade-Option und die Behandlung häufiger System-Blockierungen</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcode-Position anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Standardwerte</strong>:</p><ul><li><code>ProxyConfig.port = 8045</code>: Standard-Port des Reverse-Proxy-Dienstes</li><li><code>ProxyConfig.allow_lan_access = false</code>: Standardmäßig nur lokaler Zugriff</li><li><code>ProxyAuthMode::default() = off</code>: Standardmäßig keine Authentifizierung erforderlich</li></ul></details>',55)])])}const m=n(a,[["render",o]]);export{g as __pageData,m as default};
